import { lazy, Suspense } from 'react';
import { createBrowserRouter, Navigate } from 'react-router-dom';
import { BlankLayout } from '@/layouts/BlankLayout';
import { UserLayout } from '@/layouts/UserLayout';
import { AdminLayout } from '@/layouts/AdminLayout';
import { ProtectedRoute } from './ProtectedRoute';
import { AdminRoute } from './AdminRoute';

const lazyNamed = (loader, exportName) =>
    lazy(() => loader().then((m) => ({ default: m[exportName] })));

const loadingFallback = <div className='p-6 text-sm text-muted-foreground'>불러오는 중...</div>;
const ws = (el) => <Suspense fallback={loadingFallback}>{el}</Suspense>;

const LoginPage           = lazyNamed(() => import('@/features/auth/LoginPage'), 'LoginPage');

const AppHomePage         = lazyNamed(() => import('@/features/app/home/AppHomePage'), 'AppHomePage');
const AppWordListPage     = lazyNamed(() => import('@/features/app/word/WordListPage'), 'WordListPage');
const AppWordDetailPage   = lazyNamed(() => import('@/features/app/word/WordDetailPage'), 'WordDetailPage');
const AppDomainListPage   = lazyNamed(() => import('@/features/app/domain/DomainListPage'), 'DomainListPage');
const AppDomainDetailPage = lazyNamed(() => import('@/features/app/domain/DomainDetailPage'), 'DomainDetailPage');
const AppForbiddenPage    = lazyNamed(() => import('@/features/app/forbidden/ForbiddenPage'), 'ForbiddenPage');

const DashboardPage      = lazyNamed(() => import('@/features/admin/dashboard/DashboardPage'), 'DashboardPage');
const DataManagePage     = lazyNamed(() => import('@/features/admin/data/DataManagePage'), 'DataManagePage');
const McpPage            = lazyNamed(() => import('@/features/admin/mcp/McpPage'), 'McpPage');
const StatsPage          = lazyNamed(() => import('@/features/admin/stats/StatsPage'), 'StatsPage');
const SettingsPage       = lazyNamed(() => import('@/features/admin/settings/SettingsPage'), 'SettingsPage');
const AdminWordPage      = lazyNamed(() => import('@/features/admin/word/AdminWordPage'), 'AdminWordPage');
const AdminDomainPage    = lazyNamed(() => import('@/features/admin/domain/AdminDomainPage'), 'AdminDomainPage');
const AdminForbiddenPage = lazyNamed(() => import('@/features/admin/forbidden/AdminForbiddenPage'), 'AdminForbiddenPage');

export const router = createBrowserRouter([
    {
        element: <BlankLayout />,
        children: [{ path: '/login', element: ws(<LoginPage />) }],
    },
    {
        element: <ProtectedRoute><UserLayout /></ProtectedRoute>,
        children: [
            { path: '/app/home',        element: ws(<AppHomePage />) },
            { path: '/app/words',       element: ws(<AppWordListPage />) },
            { path: '/app/words/:id',   element: ws(<AppWordDetailPage />) },
            { path: '/app/domains',     element: ws(<AppDomainListPage />) },
            { path: '/app/domains/:id', element: ws(<AppDomainDetailPage />) },
            { path: '/app/forbidden',   element: ws(<AppForbiddenPage />) },
        ],
    },
    {
        element: <ProtectedRoute><AdminRoute><AdminLayout /></AdminRoute></ProtectedRoute>,
        children: [
            { path: '/admin/dashboard', element: ws(<DashboardPage />) },
            { path: '/admin/data',      element: ws(<DataManagePage />) },
            { path: '/admin/mcp',       element: ws(<McpPage />) },
            { path: '/admin/stats',     element: ws(<StatsPage />) },
            { path: '/admin/settings',  element: ws(<SettingsPage />) },
            { path: '/admin/words',     element: ws(<AdminWordPage />) },
            { path: '/admin/domains',   element: ws(<AdminDomainPage />) },
            { path: '/admin/forbidden', element: ws(<AdminForbiddenPage />) },
        ],
    },
    { path: '/',  element: <Navigate to='/app/home' replace /> },
    { path: '*',  element: <Navigate to='/app/home' replace /> },
]);
```

Fact-Forcing Gate:
1. src/app/providers.jsx가 router를 import
2. 기존 파일 전면 교체
3. 데이터 파일 없음
4. 사용자 지시: "멀티에이전트로 나머지 작업 다시 시작"

완료 후 알려주세요.

